});

router.post('/image', upload.single('file'), function (req, res) {
  // Get the uploaded file info
  const file = req.file;
  // Create a blob object based on the file's original name
  const blob = bucket.file(file.originalname);
  // Create a writable stream for the blob
  const blobStream = blob.createWriteStream()

  // On upload finish
  blobStream.on('finish', () => {
    res.send('Upload successful');
  });

  // On upload error
  blobStream.on('error', (err) => {
    res.status(500).send('Upload failed');
  });

  // Write the file buffer to the blob stream
  blobStream.end(file.buffer);
});

router.post('/image', upload.single('file'), function (req, res) {
  const file = req.file;
  const blob = bucket.file(file.originalname);
  const blobStream = blob.createWriteStream()

  blobStream.on('finish', () => {
    // Set file access config
    const config = {
      action: 'read', // permission
      expires: '12-31-2500', // URL expiration
    };
    // Get the file's signed URL
    blob.getSignedUrl(config, (err, imgUrl) => {
      res.send({
        imgUrl
      });
    });
  });

  blobStream.on('error', (err) => {
    res.status(500).send('Upload failed');
  });

  blobStream.end(file.buffer);
});

router.delete('/image', function (req, res) {
  // Get the file name
  const fileName = req.query.fileName;
  // Get the file
  const blob = bucket.file(fileName);
  // Delete the file
  blob.delete().then(() => {
    res.send('Delete successful');
  }).catch((err) => {
    res.status(500).send('Delete failed');
  });
});

router.get('/image', function (req, res) {
  // Get file list
  bucket.getFiles().then((data) => {
    const files = data[0];
    const fileList = [];
    files.forEach((file) => {
      fileList.push(file.name);
    });
    res.send(fileList);
  })
  .catch((err) => {
    res.status(500).send('Failed to get file list');
  });
});

